<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif;
    background: linear-gradient(135deg, #1f2430, #2b3145);
    min-height: 100vh;
    padding: 24px;
    color: #1c1e26;
  }
  h1 {
    color: #f5f6fa;
    text-align: center;
    margin: 0 0 20px;
    font-weight: 600;
  }
  .toolbar {
    display: flex;
    justify-content: center;
    gap: 8px;
    margin-bottom: 24px;
  }
  #new-card {
    padding: 10px 14px;
    border-radius: 8px;
    border: none;
    width: 320px;
    max-width: 60vw;
    font-size: 14px;
    outline: none;
  }
  #add-card {
    padding: 10px 18px;
    border-radius: 8px;
    border: none;
    background: #5b6ee1;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
    font-size: 14px;
    transition: background .15s ease;
  }
  #add-card:hover { background: #4757c9; }

  .board {
    display: flex;
    gap: 20px;
    max-width: 1100px;
    margin: 0 auto;
    align-items: flex-start;
    flex-wrap: wrap;
    justify-content: center;
  }
  .column {
    background: #f0f1f6;
    border-radius: 12px;
    width: 320px;
    min-height: 400px;
    padding: 14px;
    box-shadow: 0 6px 20px rgba(0,0,0,.25);
    display: flex;
    flex-direction: column;
    transition: background .15s ease;
  }
  .column.drag-over { background: #dfe2f2; }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
    padding-bottom: 8px;
    border-bottom: 2px solid #d3d6e6;
  }
  .col-header h2 {
    font-size: 15px;
    margin: 0;
    letter-spacing: .04em;
    text-transform: uppercase;
    color: #333a52;
  }
  .count {
    background: #5b6ee1;
    color: #fff;
    border-radius: 999px;
    padding: 2px 10px;
    font-size: 12px;
    font-weight: 700;
    min-width: 22px;
    text-align: center;
  }

  .cards {
    flex: 1;
    min-height: 60px;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }

  .card {
    background: #fff;
    border-radius: 8px;
    padding: 10px 12px;
    box-shadow: 0 2px 6px rgba(0,0,0,.12);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
    cursor: grab;
    font-size: 14px;
    word-break: break-word;
  }
  .card.dragging { opacity: .4; }

  .card-title {
    flex: 1;
  }

  .card-del {
    border: none;
    background: transparent;
    color: #b23b3b;
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
    flex-shrink: 0;
  }
  .card-del:hover { background: #fdeaea; }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="toolbar">
  <input type="text" id="new-card" placeholder="New task title...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo" data-status="todo">
    <div class="col-header">
      <h2>To Do</h2>
      <span class="count">0</span>
    </div>
    <div class="cards"></div>
  </div>

  <div class="column" id="col-doing" data-status="doing">
    <div class="col-header">
      <h2>Doing</h2>
      <span class="count">0</span>
    </div>
    <div class="cards"></div>
  </div>

  <div class="column" id="col-done" data-status="done">
    <div class="col-header">
      <h2>Done</h2>
      <span class="count">0</span>
    </div>
    <div class="cards"></div>
  </div>
</div>

<script>
(function () {
  const STORAGE_KEY = 'kanban-board-state';
  const columns = {
    todo: document.getElementById('col-todo'),
    doing: document.getElementById('col-doing'),
    done: document.getElementById('col-done')
  };

  let state = loadState();

  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed.cards)) return parsed;
      }
    } catch (e) {}
    return { cards: [], nextId: 1 };
  }

  function saveState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function render() {
    Object.values(columns).forEach(col => {
      col.querySelector('.cards').innerHTML = '';
    });

    state.cards.forEach(card => {
      const col = columns[card.status];
      if (!col) return;
      col.querySelector('.cards').appendChild(buildCardEl(card));
    });

    Object.entries(columns).forEach(([status, col]) => {
      const n = state.cards.filter(c => c.status === status).length;
      col.querySelector('.count').textContent = n;
    });
  }

  function buildCardEl(card) {
    const el = document.createElement('div');
    el.className = 'card';
    el.draggable = true;
    el.dataset.id = card.id;

    const title = document.createElement('span');
    title.className = 'card-title';
    title.textContent = card.title;

    const del = document.createElement('button');
    del.className = 'card-del';
    del.textContent = '\u2715';
    del.setAttribute('aria-label', 'Delete card');
    del.addEventListener('click', () => {
      state.cards = state.cards.filter(c => c.id !== card.id);
      saveState();
      render();
    });

    el.appendChild(title);
    el.appendChild(del);

    el.addEventListener('dragstart', e => {
      e.dataTransfer.setData('text/plain', String(card.id));
      e.dataTransfer.effectAllowed = 'move';
      el.classList.add('dragging');
    });
    el.addEventListener('dragend', () => {
      el.classList.remove('dragging');
    });

    return el;
  }

  Object.entries(columns).forEach(([status, col]) => {
    col.addEventListener('dragover', e => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      col.classList.add('drag-over');
    });
    col.addEventListener('dragleave', () => {
      col.classList.remove('drag-over');
    });
    col.addEventListener('drop', e => {
      e.preventDefault();
      col.classList.remove('drag-over');
      const id = Number(e.dataTransfer.getData('text/plain'));
      const card = state.cards.find(c => c.id === id);
      if (card) {
        card.status = status;
        saveState();
        render();
      }
    });
  });

  const input = document.getElementById('new-card');
  const addBtn = document.getElementById('add-card');

  function addCard() {
    const title = input.value.trim();
    if (!title) return;
    state.cards.push({ id: state.nextId++, title, status: 'todo' });
    saveState();
    render();
    input.value = '';
    input.focus();
  }

  addBtn.addEventListener('click', addCard);
  input.addEventListener('keydown', e => {
    if (e.key === 'Enter') addCard();
  });

  render();
})();
</script>

</body>
</html>
